/* ---------------- Free tier / paid unlock ---------------- */

// First 3 prompts in every 25-item category block are free (15 free of 125 total).
function isFreePrompt(id) {
  return ((id - 1) % 25) < 3;
}

// Suggested one-time unlock price. Shown in the UI only — actual charging happens on Selar/Gumroad.
const UNLOCK_PRICE_NAIRA = '₦12,000';

// Where "I don't have a code" sends people. Update to your real Selar/Gumroad product link.
const PURCHASE_URL = 'https://selar.co/';

// --- Unique-code system ---
// Every buyer gets their own code (format PF-XXXXXX-CC). Codes are not stored in a list here —
// they're verified with a checksum, so you can generate as many unique codes as you want with
// the companion "PromptForge Code Generator" tool (uses the same CODE_SECRET) without ever
// touching this file again. IMPORTANT: change CODE_SECRET to your own private string before
// selling, and use that same secret in the generator tool.
const CODE_SECRET = 'SAINTPAULEK-2026';
const CODE_ALPHABET = 'ABCDEFGHJKMNPQRSTUVWXYZ23456789'; // no 0/O/1/I/L, avoids confusion

function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = (hash * 31 + str.charCodeAt(i)) >>> 0;
  }
  return hash;
}
function checksumFor(payload) {
  const h = simpleHash(payload + CODE_SECRET);
  const a = CODE_ALPHABET[h % CODE_ALPHABET.length];
  const b = CODE_ALPHABET[Math.floor(h / CODE_ALPHABET.length) % CODE_ALPHABET.length];
  return a + b;
}
function isValidUnlockCode(raw) {
  const clean = raw.trim().toUpperCase().replace(/\s+/g, '');
  const match = clean.match(/^PF-([A-Z0-9]{6})-([A-Z0-9]{2})$/);
  if (!match) return false;
  const [, payload, check] = match;
  return checksumFor(payload) === check;
}

